from pydantic import BaseModel
from langchain_anthropic import ChatAnthropic

# Specialist 1: Retriever — its entire prompt is about search
RETRIEVER_PROMPT = (
    "You are a document retrieval specialist. Given a query, identify the most relevant\n"
    "information. Be concise: return only the facts directly relevant to the query.\n"
    "Do not summarise, interpret, or add context — return the relevant text verbatim."
)

# Specialist 2: Analyst — its entire prompt is about analysis
ANALYST_PROMPT = (
    "You are a data analysis specialist. Given retrieved facts, identify patterns,\n"
    "trends, and anomalies. Do not retrieve or reformulate the facts — only analyse.\n"
    "Support every claim with a specific data point from the input."
)

# Specialist 3: Writer — its entire prompt is about writing
WRITER_PROMPT = (
    "You are a technical writing specialist. Given an analysis, write a clear,\n"
    "structured report. Use headings, bullet points, and concrete examples.\n"
    "Do not add analysis not present in the input — only write."
)

def retriever_agent(query: str, documents: list[str]) -> str:
    llm = ChatAnthropic(model='claude-haiku-4-5-20251001')
    return llm.invoke([
        {"role": "system", "content": RETRIEVER_PROMPT},
        {"role": "user", "content": f"Query: {query}\nDocuments:\n" + "\n".join(documents)}
    ]).content

def analyst_agent(facts: str) -> str:
    llm = ChatAnthropic(model='claude-haiku-4-5-20251001')
    return llm.invoke([
        {"role": "system", "content": ANALYST_PROMPT},
        {"role": "user", "content": f"Facts to analyse:\n{facts}"}
    ]).content

def writer_agent(analysis: str) -> str:
    llm = ChatAnthropic(model='claude-sonnet-5')
    return llm.invoke([
        {"role": "system", "content": WRITER_PROMPT},
        {"role": "user", "content": f"Analysis to write up:\n{analysis}"}
    ]).content

# Measuring quality improvement from specialisation
import json
from langchain_anthropic import ChatAnthropic

def run_accuracy_comparison(test_cases: list[dict]) -> dict:
    """
    Compare general vs specialist agent on entity extraction.
    Each test case: {input: str, expected_people: list[str]}
    """
    general_llm = ChatAnthropic(model='claude-haiku-4-5-20251001')
    specialist_llm = ChatAnthropic(model='claude-haiku-4-5-20251001')

    GENERAL_PROMPT = 'You are a helpful assistant that can do many tasks.'
    SPECIALIST_PROMPT = (
        "You are an entity extraction specialist.\n"
        "Extract people names from text. Return a JSON array of strings.\n"
        "Rules: full names only. Normalise to First Last format.\n"
        "Return [] if no people are mentioned."
    )

    general_correct, specialist_correct = 0, 0
    for case in test_cases:
        # General agent
        g_resp = general_llm.invoke([
            {"role": "system", "content": GENERAL_PROMPT},
            {"role": "user", "content": f"Extract people names as JSON array from: {case['input']}"}
        ]).content
        try:
            g_names = json.loads(g_resp)
            if set(g_names) == set(case['expected_people']):
                general_correct += 1
        except (json.JSONDecodeError, TypeError):
            pass

        # Specialist agent
        s_resp = specialist_llm.invoke([
            {"role": "system", "content": SPECIALIST_PROMPT},
            {"role": "user", "content": case["input"]}
        ]).content
        try:
            s_names = json.loads(s_resp)
            if set(s_names) == set(case['expected_people']):
                specialist_correct += 1
        except (json.JSONDecodeError, TypeError):
            pass

    n = len(test_cases)
    return {
        'general_accuracy': general_correct / n,
        'specialist_accuracy': specialist_correct / n,
        'improvement': (specialist_correct - general_correct) / n
    }
